package embedder

import (
	"context"
	"crypto/sha256"
	"encoding/binary"
	"math"
)

// Purpose distinguishes indexing from querying.
// Backends that support task prefixes (e.g., nomic-embed-text) use this
// to prepend model-specific prefix strings.
type Purpose int

const (
	PurposeIndex Purpose = iota
	PurposeQuery
)

// Embedder abstracts all embedding backends.
// Callers pass raw text. The backend handles model-specific concerns
// (task prefixes, tokenization, batching).
type Embedder interface {
	// Embed produces a vector for a single text input.
	Embed(ctx context.Context, text string, purpose Purpose) ([]float32, error)

	// EmbedBatch produces vectors for multiple texts.
	// Returns vectors in the same order as input texts.
	EmbedBatch(ctx context.Context, texts []string, purpose Purpose) ([][]float32, error)

	// Dimensions returns the vector dimensionality (e.g., 768).
	Dimensions() int

	// MaxTokens returns the model's context window in tokens (e.g., 8192).
	MaxTokens() int

	// Close releases model resources.
	Close() error
}

// MockEmbedder produces deterministic vectors for testing.
// Each unique text input maps to a stable vector based on its content hash.
type MockEmbedder struct {
	dims      int
	maxTokens int
}

// NewMockEmbedder creates a mock embedder with the given dimensionality.
func NewMockEmbedder(dims int) *MockEmbedder {
	return &MockEmbedder{dims: dims, maxTokens: 8192}
}

func (m *MockEmbedder) Embed(_ context.Context, text string, _ Purpose) ([]float32, error) {
	return deterministicVector(text, m.dims), nil
}

func (m *MockEmbedder) EmbedBatch(_ context.Context, texts []string, purpose Purpose) ([][]float32, error) {
	result := make([][]float32, len(texts))
	for i, text := range texts {
		result[i] = deterministicVector(text, m.dims)
	}
	return result, nil
}

func (m *MockEmbedder) Dimensions() int { return m.dims }
func (m *MockEmbedder) MaxTokens() int  { return m.maxTokens }
func (m *MockEmbedder) Close() error    { return nil }

// deterministicVector produces a stable, normalised float32 vector from text.
func deterministicVector(text string, dims int) []float32 {
	h := sha256.Sum256([]byte(text))
	vec := make([]float32, dims)
	var sumSq float64
	for i := range vec {
		// Use bytes from the hash cyclically to seed values
		idx := i % len(h)
		bits := uint32(h[idx]) ^ uint32(h[(idx+1)%len(h)])<<8 ^ uint32(h[(idx+2)%len(h)])<<16 ^ uint32(i)
		vec[i] = float32(int32(bits)%1000) / 1000.0
		sumSq += float64(vec[i]) * float64(vec[i])
	}
	// Normalise to unit vector
	norm := float32(math.Sqrt(sumSq))
	if norm > 0 {
		for i := range vec {
			vec[i] /= norm
		}
	}
	return vec
}

// deterministicVectorFromSeed produces a stable vector from a uint64 seed.
func deterministicVectorFromSeed(seed uint64, dims int) []float32 {
	b := make([]byte, 8)
	binary.LittleEndian.PutUint64(b, seed)
	h := sha256.Sum256(b)
	vec := make([]float32, dims)
	var sumSq float64
	for i := range vec {
		idx := i % len(h)
		bits := uint32(h[idx]) ^ uint32(h[(idx+1)%len(h)])<<8 ^ uint32(i)
		vec[i] = float32(int32(bits)%1000) / 1000.0
		sumSq += float64(vec[i]) * float64(vec[i])
	}
	norm := float32(math.Sqrt(sumSq))
	if norm > 0 {
		for i := range vec {
			vec[i] /= norm
		}
	}
	return vec
}
